1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const BLOCK_PREMIUM = 60;
4	const BLOCK_SIZE = 3;
5	
6	const BASE_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	function calculateComponentPremium(items: any[]): number {
16	  const counts: Record<string, number> = {};
17	  for (const item of items) {
18	    if (COMPONENT_TYPES.has(item.type)) {
19	      counts[item.type] = (counts[item.type] ?? 0) + 1;
20	    }
21	  }
22	  let premium = 0;
23	  for (const count of Object.values(counts)) {
24	    if (count === BLOCK_SIZE) {
25	      premium += BLOCK_PREMIUM;
26	    } else {
27	      premium += count * COMPONENT_PREMIUM;
28	    }
29	  }
30	  return premium;
31	}
32	
33	function calculateItemPremium(item: any): { base: number; total: number } {
34	  if (COMPONENT_TYPES.has(item.type)) {
35	    return { base: 0, total: 0 };
36	  }
37	  if (!(item.type in BASE_PREMIUMS)) {
38	    throw new Error(`Unknown item type: ${item.type}`);
39	  }
40	  const base = BASE_PREMIUMS[item.type];
41	  let total = base;
42	  if (item.cursed) {
43	    total += base * 0.5;
44	  }
45	  if (item.enchantment >= 5) {
46	    total += base * 0.3;
47	  }
48	  return { base, total };
49	}
50	
51	function calculateQuotePremium(items: any[], customer: any, contractIndex: number): number {
52	  const itemPremiums = items.map((item) => calculateItemPremium(item));
53	  const itemTotal = itemPremiums.reduce((sum, p) => sum + p.total, 0);
54	  const nonComponentBase = itemPremiums.reduce((sum, p) => sum + p.base, 0);
55	  const componentTotal = calculateComponentPremium(items);
56	  const policyBasePremium = nonComponentBase + componentTotal;
57	  const firstInsurance = policyBasePremium * 0.1;
58	  const loyalty = customer.yearsWithMHPCO >= 2 ? policyBasePremium * 0.2 : 0;
59	  const followUp = contractIndex > 0 ? policyBasePremium * 0.15 : 0;
60	  return Math.ceil(PROCESSING_FEE + itemTotal + componentTotal + firstInsurance - loyalty - followUp);
61	}
62	
63	export function processScenario(scenario: any): any {
64	  let quoteIndex = 0;
65	  const results = scenario.steps.map((step: any) => {
66	    if (step.op === "quote") {
67	      return { premium: calculateQuotePremium(step.items, scenario.customer, quoteIndex++) };
68	    }
69	  });
70	  return { results };
71	}
